import { type PropsWithChildren } from 'react';

import {
  graphContainer,
  legendContainer,
  legendResizeLine,
  resizeContainer,
} from './styles.sty.js';
import { Flex } from '../../../../../layouts/flex/Flex.js';
import { LegendSizeContext } from '../../legend/shared/context/LegendSizeContext.js';
import { GraphSizeContext } from '../context/GraphSize.context.js';
import { useChartLayoutLoading } from '../hooks/useChartLayoutLoading.js';
import { useChartLayoutOrientation } from '../hooks/useChartLayoutOrientation.js';
import { useChartLayoutSize } from '../hooks/useChartLayoutSize.js';
import { useChartLayoutTemplate } from '../hooks/useChartLayoutTemplate.js';
import { useResizableLayout } from '../hooks/useResizableLayout.js';
import { isVertical as isVerticalFn } from '../utils/orientation.js';

interface ResizableChartLayoutProps {
  onResize?: (ratio: number) => void;
  showResizer: boolean;
  showLegend: boolean;
}

export const ResizableChartLayout = ({
  onResize,
  showResizer,
  showLegend,
}: PropsWithChildren<ResizableChartLayoutProps>) => {
  const { orientation } = useChartLayoutOrientation();
  const loading = useChartLayoutLoading();
  const containerUsableArea = useChartLayoutSize();
  const { legendArea, graphArea } = useChartLayoutTemplate();
  const isVertical = isVerticalFn(orientation);

  const {
    legendWidth,
    legendHeight,
    graphSize,
    legendContainerRef,
    legendResizeLineRef,
    legendResizeContainerRef,
  } = useResizableLayout(
    containerUsableArea.width,
    containerUsableArea.height,
    orientation,
    showResizer,
    showLegend,
    onResize,
  );

  return (
    <>
      <div className={graphContainer({ loading })}>
        <GraphSizeContext.Provider value={graphSize}>
          {graphArea}
        </GraphSizeContext.Provider>
      </div>
      {showLegend && showResizer && (
        <Flex
          ref={legendResizeContainerRef}
          alignItems="center"
          justifyContent={isVertical ? 'center' : 'flex-end'}
          className={resizeContainer({ orientation, loading })}
        >
          <div
            data-testid="legend-resize-line"
            ref={legendResizeLineRef}
            className={legendResizeLine({ orientation })}
          />
        </Flex>
      )}
      {showLegend && (
        <div
          ref={legendContainerRef}
          className={legendContainer({
            orientation,
            loading,
          })}
        >
          <LegendSizeContext.Provider
            value={{ width: legendWidth, height: legendHeight }}
          >
            {legendArea}
          </LegendSizeContext.Provider>
        </div>
      )}
    </>
  );
};

ResizableChartLayout['displayName'] = 'ResizableChartLayout';
